import * as react_jsx_runtime from 'react/jsx-runtime';
import * as react_hook_form from 'react-hook-form';
import { FieldValues, FieldPath, ControllerProps } from 'react-hook-form';
import { Label } from './label.js';
import { Slot } from 'radix-ui';
import * as React from 'react';

/**
 * Wraps `react-hook-form`'s `FormProvider`. Place this at the root of your
 * form, passing the `useForm()` return value as props.
 *
 * ### Example Usage
 *
 * ```tsx
 * const form = useForm<FormValues>();
 *
 * <Form {...form}>
 *   <form onSubmit={form.handleSubmit(onSubmit)}>
 *     <FormField
 *       control={form.control}
 *       name="email"
 *       render={({field}) => (
 *         <FormItem>
 *           <FormLabel>Email</FormLabel>
 *           <FormControl><Input {...field} /></FormControl>
 *           <FormMessage />
 *         </FormItem>
 *       )}
 *     />
 *   </form>
 * </Form>
 * ```
 */
declare const Form: <TFieldValues extends FieldValues, TContext = any, TTransformedValues = TFieldValues>(props: react_hook_form.FormProviderProps<TFieldValues, TContext, TTransformedValues>) => React.JSX.Element;
/**
 * Returns the current field's state, IDs for aria wiring, and react-hook-form
 * field state. Must be called inside a `<FormField>`.
 */
declare function useFormField(): {
    invalid: boolean;
    isDirty: boolean;
    isTouched: boolean;
    isValidating: boolean;
    error?: react_hook_form.FieldError;
    id: string;
    name: string;
    formItemId: string;
    formDescriptionId: string;
    formMessageId: string;
};
/**
 * Connects a form control to `react-hook-form` via `Controller`. Pass a
 * `render` prop that receives `{field, fieldState, formState}`.
 *
 * ### Example Usage
 *
 * ```tsx
 * <FormField
 *   control={form.control}
 *   name="username"
 *   render={({field}) => (
 *     <FormItem>
 *       <FormLabel>Username</FormLabel>
 *       <FormControl><Input {...field} /></FormControl>
 *       <FormMessage />
 *     </FormItem>
 *   )}
 * />
 * ```
 */
declare function FormField<TFieldValues extends FieldValues = FieldValues, TName extends FieldPath<TFieldValues> = FieldPath<TFieldValues>>(props: ControllerProps<TFieldValues, TName>): react_jsx_runtime.JSX.Element;
/**
 * Wraps a single field with a stable `id` context used by `FormLabel`,
 * `FormControl`, `FormDescription`, and `FormMessage` for aria wiring.
 */
declare function FormItem({ className, ...props }: React.ComponentProps<'div'>): react_jsx_runtime.JSX.Element;
/**
 * A `Label` pre-wired to the sibling `FormControl` via `htmlFor`.
 * Turns destructive-colored when the field has a validation error.
 */
declare function FormLabel({ className, ...props }: React.ComponentProps<typeof Label>): react_jsx_runtime.JSX.Element;
/**
 * A `Slot` that injects `id`, `aria-describedby`, and `aria-invalid` onto
 * the wrapped control so screen readers associate it with its label,
 * description, and error message automatically.
 */
declare function FormControl({ ...props }: React.ComponentProps<typeof Slot.Root>): react_jsx_runtime.JSX.Element;
/**
 * Helper text displayed below the control. Wired to `aria-describedby` on
 * the `FormControl`.
 */
declare function FormDescription({ className, ...props }: React.ComponentProps<'p'>): react_jsx_runtime.JSX.Element;
/**
 * Renders the field's validation error. Falls back to `children` when there
 * is no error. Renders nothing when both are absent.
 */
declare function FormMessage({ className, children, ...props }: React.ComponentProps<'p'>): react_jsx_runtime.JSX.Element | null;

export { Form, FormControl, FormDescription, FormField, FormItem, FormLabel, FormMessage, useFormField };
